    "            'Study_Hours_per_Week','Stress_Level (1-10)','Sleep_Hours_per_Night']\n",
    "\n",
    "corr = df_clean[NUM_COLS].corr()\n",
    "top_corr = (corr['Total_Score'].drop('Total_Score')\n",
    "                               .abs()\n",
    "                               .sort_values(ascending=False))\n",
    "print(\"\\nTop features correlated with Total_Score:\")\n",
    "print(top_corr.head(8).to_string())\n",
    "\n",
    "fig2, axes = plt.subplots(2, 2, figsize=(16, 12), facecolor=BG)\n",
    "fig2.suptitle(\"Correlation & Score Breakdown\",\n",
    "              fontsize=18, fontweight='bold', color=ACCENT, y=0.99)\n",
    "\n",
    "# Correlation heatmap\n",
    "mask = np.triu(np.ones_like(corr, dtype=bool))\n",
    "sns.heatmap(corr, mask=mask, annot=True, fmt='.2f', cmap='RdYlGn',\n",
    "            linewidths=0.5, ax=axes[0, 0], vmin=-1, vmax=1,\n",
    "            annot_kws={'size': 7})\n",
    "axes[0, 0].set_title('Feature Correlation Matrix', fontweight='bold', color=ACCENT)\n",
    "axes[0, 0].tick_params(axis='x', rotation=45, labelsize=8)\n",
    "\n",
    "# Score components boxplot by grade\n",
    "score_cols = ['Midterm_Score','Final_Score','Assignments_Avg',\n",
    "              'Quizzes_Avg','Projects_Score']\n",
    "melted = (df_clean[['Grade'] + score_cols]\n",
    "          .melt(id_vars='Grade', var_name='Component', value_name='Score'))\n",
    "sns.boxplot(data=melted[melted['Grade'].isin(GRADE_ORDER)],\n",
    "            x='Component', y='Score', hue='Grade',\n",
    "            hue_order=GRADE_ORDER, palette=GRADE_COLORS,\n",
    "            linewidth=0.8, ax=axes[0, 1])\n",
    "axes[0, 1].set_title('Score Components by Grade', fontweight='bold', color=ACCENT)\n",
    "axes[0, 1].tick_params(axis='x', rotation=30, labelsize=8)\n",
    "\n",
    "# Avg stress level by grade\n",
    "stress_grade = (df_clean.groupby('Grade')['Stress_Level (1-10)']\n",
    "                         .mean().reindex(GRADE_ORDER))\n",
    "colors_list = [GRADE_COLORS[g] for g in GRADE_ORDER]\n",
